output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?country WHERE {
  ?country wdt:P31 wd:Q6256 ; wdt:P30 wd:Q15 ; wdt:P4529 ?percentage .
  FILTER(?percentage > 5)
}

args.sparql:
SELECT ?country WHERE {
  ?country wdt:P31 wd:Q6256.
  ?country wdt:P30 wd:Q15.
  ?country wdt:P1082 ?totalPopulation.
  ?country p:P1082 [
    ps:P1082 ?aged65Count;
    pq:P148 wd:Q117131136
  ].
  FILTER(?aged65Count > 0).
  FILTER(?totalPopulation > 0).
  FILTER((?aged65Count * 100.0) / ?totalPopulation > 5)
}

